import type { ButtonProps } from ':components/Button/Button.types';
/**
 * Пропсы для одной кнопки в ButtonSet
 * Исключает size, так как размер задается единый для всех кнопок через проп компонента
 */
export interface ButtonSetButton extends Omit<ButtonProps, 'size'> {
    /**
     * Уникальный идентификатор кнопки (для key)
     */
    id?: string;
}
/**
 * Массив кнопок для ButtonSet
 */
export type ButtonSetButtonsArray = ButtonSetButton[];
/**
 * Пропсы для компонента ButtonSet
 */
export interface ButtonSetProps {
    /**
     * Массив кнопок
     */
    buttons: ButtonSetButtonsArray;
    /**
     * Единый размер для всех кнопок
     * Отступ между кнопками автоматически зависит от размера:
     * - small -> 6px
     * - medium -> 8px
     * - large -> 10px
     * @default 'small'
     */
    size?: 'small' | 'medium' | 'large';
    /**
     * Направление расположения кнопок
     * @default 'horizontal'
     */
    direction?: 'horizontal' | 'vertical';
    /**
     * Дополнительный CSS класс
     */
    className?: string;
    /**
     * Идентификатор для тестирования
     * @default 'ButtonSet'
     */
    dataTestId?: string;
}
